16	const PROCESSING_FEE = 5;
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	const FIRST_INSURANCE_SURCHARGE = 0.1;
24	
25	// Rounds up in MHPCO's favor, guarding against floating-point drift
26	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
27	const roundUpInFavor = (amount: number): number =>
28	  Math.ceil(Number(amount.toFixed(6)));
29	
30	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
31	const COMPONENT_BASE_PREMIUM = 25;
32	const BLOCK_SIZE = 3;
33	const BLOCK_BASE_PREMIUM = 60;
34	
35	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
36	
37	// A same-type group of exactly BLOCK_SIZE components forms one block priced at
38	// BLOCK_BASE_PREMIUM; any other count is priced per component. (Multi-block and
39	// block-plus-leftover pricing are not yet implemented.)
40	const componentGroupBasePremium = (count: number): number =>
41	  count === BLOCK_SIZE
42	    ? BLOCK_BASE_PREMIUM
43	    : count * COMPONENT_BASE_PREMIUM;
44	
45	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
46	
47	const countByType = (items: Item[]): Record<string, number> =>
48	  items.reduce<Record<string, number>>((counts, item) => {
49	    counts[item.type] = (counts[item.type] ?? 0) + 1;
50	    return counts;
51	  }, {});
52	
53	const sum = (values: number[]): number =>
54	  values.reduce((running, value) => running + value, 0);
55	
56	const basePremiumTotal = (items: Item[]): number => {
57	  const mainItems = items.filter((item) => !isComponent(item));
58	  const components = items.filter(isComponent);
59	
60	  const mainItemsTotal = sum(mainItems.map(itemBasePremium));
61	  const componentsTotal = sum(
62	    Object.values(countByType(components)).map(componentGroupBasePremium),
63	  );
64	
65	  return mainItemsTotal + componentsTotal;
66	};
67	
68	export const quote = (customer: Customer, items: Item[]): QuoteResult => {
69	  const itemsPremiumTotal =
70	    basePremiumTotal(items) * (1 + FIRST_INSURANCE_SURCHARGE);
71	  const exactPremium = itemsPremiumTotal + PROCESSING_FEE;
72	  return { premium: roundUpInFavor(exactPremium) };
73	};
74	
75	export const claim = (...args: unknown[]): unknown => {
76	  return undefined;
77	};
